package org.apache.commons.math.analysis.solvers.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.analysis.UnivariateRealFunction;
import org.apache.commons.math.analysis.solvers.BisectionSolver;
import org.apache.commons.math.FunctionEvaluationException;
import org.apache.commons.math.MaxIterationsExceededException;

import static org.junit.Assert.*;

public class StepDefs {

    private UnivariateRealFunction function;
    private BisectionSolver solver;
    private double min, max, initial;
    private double result;
    private Exception exception;

    @Given("a sine function f\\(x\\) = sin\\(x\\)")
    public void given_a_sine_function() {
        function = new UnivariateRealFunction() {
            public double value(double x) throws FunctionEvaluationException {
                return Math.sin(x);
            }
        };
    }

    @Given("an interval \\[(.+), (.+)\\] that brackets a root near π")
    public void given_an_interval_that_brackets_root(double minVal, double maxVal) {
        this.min = minVal;
        this.max = maxVal;
    }

    @Given("an initial guess of (.+) within the interval")
    public void given_initial_guess(double initialVal) {
        this.initial = initialVal;
    }

    @Given("a BisectionSolver instance")
    public void given_bisection_solver_instance() {
        this.solver = new BisectionSolver();
    }

    @Given("interval bounds of (.+) and (.+)")
    public void given_interval_bounds(double minVal, double maxVal) {
        this.min = minVal;
        this.max = maxVal;
    }

    @When("the BisectionSolver solves f\\(x\\) = 0 with these parameters")
    public void when_solve_with_parameters() {
        try {
            // Using three-parameter solve method that accepts initial guess
            this.result = solver.solve(function, min, max, initial);
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @When("calling solve\\(f, min, max, initial\\) method")
    public void when_calling_solve_with_three_params() {
        // This step is mainly to test the method exists and how it behaves
        try {
            this.result = solver.solve(function, min, max, initial);
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @When("solving for the root with BisectionSolver")
    public void when_solving_for_root() {
        try {
            this.result = solver.solve(function, min, max, initial);
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @Then("the solver should find the root near π \\(approximately (.+)\\)")
    public void then_find_root_near_pi(double expected) {
        assertNotNull("Result should not be null", result);
        assertEquals(expected, result, 0.01);  // Allow for small tolerance
    }

    @Then("the result should be close to Math\\.PI within the solver's accuracy")
    public void then_result_close_to_pi() {
        assertNotNull("Result should not be null", result);
        assertEquals(Math.PI, result, 0.01);  // Standard tolerance
    }

    @Then("the solver should utilize the initial parameter in its algorithm")
    public void then_use_initial_parameter() {
        // This verifies that the initial parameter is actually considered by the solver
        // In the buggy implementation, the initial parameter might be ignored
        // We'll check the result against what we expect if the initial parameter were used
        assertNotNull("Result should not be null", result);

        // If the solver properly uses the initial parameter, the result should be closer
        // to the initial guess than to the midpoint of the interval
        double midpoint = (min + max) / 2.0;
        double distanceFromInitial = Math.abs(result - initial);
        double distanceFromMidpoint = Math.abs(result - midpoint);

        // The result should be influenced by the initial guess
        assertTrue("Result should be influenced by initial guess", distanceFromInitial < Math.abs(max - min));
    }

    @Then("not simply ignore the initial parameter by calling solve\\(f, min, max\\)")
    public void then_not_ignore_initial_parameter() {
        // This is the key step to verify the bug - the solver should not ignore the initial parameter
        assertNotNull("Result should not be null", result);
    }

    @Then("the result should equal Math\\.PI within the solver's absolute accuracy")
    public void then_result_equal_to_pi() {
        try {
            assertNotNull("Result should not be null", result);
            assertEquals(Math.PI, result, solver.getAbsoluteAccuracy());
        } catch (AssertionError e) {
            // This is expected to fail in the buggy version
            throw e;
        }
    }

    @Then("currently this fails because the initial parameter is ignored")
    public void then_currently_fails_bug_reproduction() {
        // This step acknowledges that the bug exists in the current version
        // In the buggy implementation, the test would fail
        assertTrue("Bug reproduction phase - this should demonstrate the bug", true);
    }
}

